from dataclasses import dataclass
from typing import List, Dict


@dataclass(frozen=True)
class LineItem:
    sku: str
    name: str
    quantity: int
    unit_price_cents: int

    @property
    def line_total_cents(self) -> int:
        return self.quantity * self.unit_price_cents


@dataclass(frozen=True)
class Purchase:
    order_id: str
    customer_id: str
    items: List[LineItem]
    currency: str

    @property
    def total_cents(self) -> int:
        return sum(item.line_total_cents for item in self.items)


# Predefined dictionary of purchases keyed by order_id
PURCHASES: Dict[str, Purchase] = {
    "ORD-1001": Purchase(
        order_id="ORD-1001",
        customer_id="CUST-42",
        items=[
            LineItem(sku="SKU-RED-TS", name="Red T-Shirt", quantity=2, unit_price_cents=1999),
            LineItem(sku="SKU-MUG-BLK", name="Black Mug", quantity=1, unit_price_cents=1299),
        ],
        currency="USD",
    ),
    "ORD-1002": Purchase(
        order_id="ORD-1002",
        customer_id="CUST-77",
        items=[
            LineItem(sku="SKU-HAT-BLU", name="Blue Hat", quantity=1, unit_price_cents=2499),
        ],
        currency="USD",
    ),
}


def get_purchase_by_id(order_id: str) -> Purchase:
    """
    Fetch a Purchase by its order ID.

    Args:
        order_id: The order ID to look up.

    Returns:
        The matching Purchase object.

    Raises:
        ValueError: If no purchase exists for the given order ID.
    """
    try:
        return PURCHASES[order_id]
    except KeyError:
        raise ValueError(f"Purchase with order ID '{order_id}' not found")

turn2_code:
import string

ORDERS = {
    "1001": {"customer_name": "Alice Smith", "total_amount": 149.99},
    "1002": {"customer_name": "Bob Johnson", "total_amount": 89.50},
    "1003": {"customer_name": "Carol Lee", "total_amount": 230.00},
}


class _Placeholder:
    def __init__(self, key: str):
        self.key = key

    def __format__(self, format_spec: str) -> str:
        # Leave unknown placeholders unchanged, regardless of format spec
        return "{" + self.key + "}"

    def __str__(self) -> str:
        return "{" + self.key + "}"


class _SafeFormatter(string.Formatter):
    def get_value(self, key, args, kwargs):
        if isinstance(key, str):
            return kwargs.get(key, _Placeholder(key))
        return super().get_value(key, args, kwargs)


def print_order_details(order_id, template=None):
    """
    Retrieve and format basic order details (customer name and total amount)
    for the given order_id.

    Args:
        order_id (str|int): The identifier of the order to look up.
        template (str|None): A template string with placeholders such as
            '{order_id}', '{customer_name}', and '{total_amount}'. Unknown
            placeholders are left unchanged. If None, a default template
            is used.

    Returns:
        str: The formatted string with order details, or a not-found message.
    """
    oid = str(order_id)
    order = ORDERS.get(oid)
    if not order:
        return f"Order {oid} not found."

    customer_name = order.get("customer_name", "Unknown Customer")
    total_amount = order.get("total_amount", 0.0)

    context = {
        "order_id": oid,
        "customer_name": customer_name,
        "total_amount": total_amount,
    }

    if template is None:
        template = "Order {order_id} - Customer: {customer_name}\nTotal Amount: ${total_amount:,.2f}"

    formatter = _SafeFormatter()
    return formatter.format(template, **context)

